/* ===== Inhalte: Karteikarten & Befehlskarten =====
 * CRAB_QUIZ – Verständnis-Karteikarten der Krabbe Kralle (Multiple Choice).
 * CMD_CARDS – Befehls-Karten: Aufgabe + akzeptierte Eingaben (Spaced Repetition).
 */

/* ---------- Karteikarten (Krabbe Kralle) ---------- */
export const CRAB_QUIZ = [
  { id: "q-ch1-1", q: "Welches Problem lösen Software-Container hauptsächlich?", options: ["Eine App läuft mit allem Drumherum überall gleich – Laptop, Server, Cloud.", "Sie machen Programme automatisch schneller.", "Sie verschlüsseln Programme gegen Angriffe.", "Sie sparen Speicherplatz."], correct: 0, explain: "Container packen die App mit allen Abhängigkeiten in eine genormte Box. „Bei mir läuft's aber!“ ist damit Geschichte." },
  { id: "q-ch1-2", q: "Image vs. Container – was ist was?", options: ["Image = Bauplan/Vorlage, Container = laufende Instanz davon.", "Kein Unterschied, zwei Wörter für dasselbe.", "Container = Vorlage, Image = das laufende Programm.", "Images sind für Linux, Container für Windows."], correct: 0, explain: "Tiefkühlpizza (Image) und Pizza im Ofen (Container): Aus einem Image kannst du viele Container starten." },
  { id: "q-ch1-3", q: "Was ist Docker Hub?", options: ["Eine Registry – ein öffentlicher „Supermarkt“ für fertige Images.", "Das Hauptquartier der Firma Docker.", "Ein USB-Hub für Container.", "Ein Überwachungstool."], correct: 0, explain: "Eine Registry speichert Images. docker pull nginx lädt z.B. das nginx-Image von Docker Hub." },
  { id: "q-ch1-4", q: "Was zeigt der Befehl docker ps?", options: ["Alle gerade laufenden Container.", "Alle heruntergeladenen Images.", "Die Prozessorlast.", "Alle Images auf Docker Hub."], correct: 0, explain: "docker ps = laufende Container. Mit -a („all“) siehst du auch die gestoppten." },
  { id: "q-ch1-5", q: "Woraus besteht ein Docker-Image intern?", options: ["Aus übereinandergestapelten Schichten (Layern) – unten die Basis, oben die App.", "Aus einer einzigen großen Datei ohne Struktur.", "Aus dem Quellcode der App.", "Aus einer virtuellen Festplatte mit Betriebssystem."], correct: 0, explain: "Image = Schichtstapel: Base-Image unten, dann Bibliotheken, oben die App. Unveränderte Schichten kommen aus dem Cache – deshalb sind gute Schicht-Reihenfolgen so wichtig (Stapel-Spiel bei Bo!)." },
  { id: "q-ch1-6", q: "Was macht <code>docker build -t name:tag .</code>?", options: ["Es baut aus dem Dockerfile ein eigenes Image und gibt ihm mit -t einen Namen.", "Es lädt ein fertiges Image aus der Registry.", "Es startet einen Container aus einem Image.", "Es löscht alle ungenutzten Images."], correct: 0, explain: "build liest den Bauplan (Dockerfile) im aktuellen Ordner (der Punkt) und schichtet daraus ein Image. pull holt nur Fertiges – build stellt Eigenes her. Mit docker tag gibst du demselben Image weitere Namen (z.B. :latest – ein Konventions-Name, nicht automatisch die neueste Version)." },
  { id: "q-ch1-7", q: "Was bewirkt <code>-d</code> (detached) bei <code>docker run</code>?", options: ["Der Container läuft abgekoppelt im Hintergrund weiter – das Terminal ist sofort wieder frei.", "Der Container wird gelöscht, sobald er fertig ist.", "Der Container startet im Debug-Modus.", "Docker lädt das Image vor dem Start neu herunter."], correct: 0, explain: "Ohne -d (attached) hängt das Terminal am Container und zeigt dessen Ausgabe – die Konsole ist blockiert, bis er endet. Mit -d (detached) koppelt er sich ab und läuft im Hintergrund weiter; das „Funkgerät“ ist sofort frei für den nächsten Befehl." },
  { id: "q-ch1-8", q: "Bei <code>docker run -d --name webserver nginx</code> – was ist <code>webserver</code> und was <code>nginx</code>?", options: ["webserver = dein frei gewählter Container-Name (--name), nginx = das Image, aus dem der Container entsteht.", "webserver = das Image, nginx = der Container-Name.", "Beides sind Images, die zusammen geladen werden.", "webserver ist ein Tippfehler – nur nginx zählt."], correct: 0, explain: "Hinter --name steht DEIN Wunschname (frei wählbar – auch „meine-kiste“). Ganz hinten steht immer das Image: die Vorlage/der Bausatz, aus dem der Container gestartet wird – und das muss als Bauplan existieren. Muster: docker run [optionen] --name <wunschname> <image>." },
  { id: "q-ch1-9", q: "Du willst sehen, welche Dateien im aktuellen Ordner liegen. Welcher Befehl?", options: ["<code>ls</code> – listet den Inhalt des aktuellen Ordners auf.", "<code>cat</code> – das zeigt den Inhalt EINER Datei, nicht die Liste.", "<code>cd</code> – das wechselt nur den Ordner.", "<code>docker ps</code> – das zeigt Container, keine Dateien."], correct: 0, explain: "ls = „list“: zeigt, was im Ordner liegt (Dateien/Verzeichnisse). cat <datei> zeigt dagegen den INHALT einer einzelnen Datei. Faustregel: erst ls (was ist da?), dann cat <datei> (was steht drin?)." },
  { id: "q-ch2-1", q: "Wofür braucht man Kubernetes, wenn es Docker gibt?", options: ["Es verwaltet viele Container auf vielen Servern automatisch: neu starten, verteilen, skalieren.", "Es ersetzt Docker, weil Docker veraltet ist.", "Es macht Container kleiner.", "Es ist nur eine grafische Oberfläche für Docker."], correct: 0, explain: "Docker startet Container, Kubernetes orchestriert sie in großem Stil – die Hafenmeisterei für hunderte Kisten." },
  { id: "q-ch2-2", q: "Was ist ein Pod?", options: ["Die kleinste Einheit in Kubernetes – meist genau ein Container drin.", "Ein anderes Wort für einen Server.", "Eine Gruppe von mindestens zehn Containern.", "Das Konfigurationsformat von Kubernetes."], correct: 0, explain: "Kubernetes verwaltet nie Container direkt, sondern immer Pods – die Liegeplätze mit den Kisten drauf." },
  { id: "q-ch2-3", q: "Was ist ein Node?", options: ["Ein einzelner Server, der zum Cluster gehört und Pods ausführt.", "Ein Backup des Clusters.", "Ein spezieller Pod für Datenbanken.", "Das Kabel zwischen zwei Clustern."], correct: 0, explain: "Im Hafenbild: ein Steg. Mehrere Nodes zusammen bilden den Cluster." },
  { id: "q-ch2-podnode", q: "Pod vs. Node – was ist der Unterschied?", options: ["Node = die Maschine (Server/VM), die rechnet; Pod = die kleinste laufende Einheit (meist 1 Container), die AUF einem Node liegt. Ein Node trägt viele Pods.", "Pod = die Maschine, Node = die laufende App darauf.", "Pod und Node sind dasselbe – nur in verschiedenen Kubernetes-Versionen.", "Node = ein einzelner Container, Pod = eine Gruppe von Servern."], correct: 0, explain: "Maschine ↔ laufende Einheit: Der Scheduler verteilt die <b>vergänglichen</b> Pods auf die festen Nodes – fällt ein Pod (oder ein ganzer Node) aus, startet Kubernetes woanders Ersatz. Darum verwaltet K8s nie Container direkt, sondern Pods als kleinste planbare Einheit. Eselsbrücke: <b>Pod</b> = „Schote/Hülse“ (wie die Erbsenschote – passt zum Docker-Wal & Containerschiff; auch eine Walschule heißt „pod“), <b>Node</b> = „Knoten“ im Cluster-Netz. Im Hafenbild: Node = Steg, Pod = Liegeplatz darauf." },
  { id: "q-ch2-4", q: "Ein Container stürzt nachts um 3 Uhr ab. Was passiert?", options: ["Kubernetes merkt es und startet automatisch Ersatz.", "Der Admin bekommt einen Anruf.", "Der Pod bleibt kaputt bis zum Morgen.", "Der Cluster fährt sicherheitshalber herunter."], correct: 0, explain: "Self-Healing: Kubernetes überwacht den Soll-Zustand und stellt ihn automatisch wieder her." },
  { id: "q-ch2-5", q: "Ein Pod heißt <code>kantine-9f4c2-x7k1</code>. Woher kommt das kryptische Anhängsel?", options: ["Kubernetes vergibt es automatisch, damit jeder Pod einen eindeutigen Namen hat.", "Der Admin hat es von Hand eingetippt.", "Es ist die Versionsnummer der laufenden App.", "Es ist die IP-Adresse des Pods in Kurzform."], correct: 0, explain: "Pods aus einem Deployment werden automatisch benannt: <Deployment>-<ReplicaSet-Hash>-<Pod-Hash>. So kollidiert kein Name, auch wenn ständig neue Pods nachstarten. Die noch kryptischere CONTAINER ID in <code>docker ps</code> vergibt analog die Container-Runtime – beides sind eindeutige, maschinengemachte Stempel, keine Handarbeit." },
  { id: "q-ch3-1", q: "Warum erstellt man Pods über ein Deployment statt direkt?", options: ["Pods sind sterblich – das Deployment ersetzt tote Pods automatisch und hält die Anzahl.", "Einzelne Pods verbrauchen mehr Speicher.", "Pods brauchen sonst Admin-Rechte.", "Direkte Pods sind verboten."], correct: 0, explain: "Das Deployment ist der Dauerauftrag: „Halte immer N Kopien am Laufen.“" },
  { id: "q-ch3-2", q: "Du löschst einen Pod eines Deployments (replicas: 3). Was passiert?", options: ["Kubernetes startet sofort einen neuen – es sollen ja 3 sein.", "Es laufen dauerhaft nur noch 2.", "Das Deployment wird ungültig.", "Kubernetes fragt erst nach."], correct: 0, explain: "Soll (3) vs. Ist (2) → Differenz wird sofort behoben. Self-Healing live!" },
  { id: "q-ch3-3", q: "Wozu braucht man einen Service?", options: ["Als feste, stabile Adresse vor den Pods – deren Namen und IPs wechseln ständig.", "Um Pods schneller zu machen.", "Als Backup für Deployments.", "Services starten Nodes neu."], correct: 0, explain: "Der Empfangstresen: Wer die App erreichen will, redet mit dem Service – der leitet an die lebenden Pods weiter." },
  { id: "q-ch4-1", q: "Imperativ vs. deklarativ?", options: ["Imperativ = einzelne Befehle rufen. Deklarativ = Wunschzustand in eine Datei schreiben.", "Imperativ ist für Linux, deklarativ für Windows.", "Deklarativ heißt: mit der Maus klicken.", "Kein Unterschied."], correct: 0, explain: "Deklarativ ist der Profi-Standard, weil die Dateien in Git versioniert werden können." },
  { id: "q-ch4-2", q: "Was gibt das Feld kind in einem Manifest an?", options: ["Welche Art von Ressource beschrieben wird – z.B. Deployment oder Service.", "Wie freundlich der Cluster antworten soll.", "Die Kubernetes-Version.", "Den Namen des Erstellers."], correct: 0, explain: "kind: Deployment, kind: Service … es bestimmt, was die Datei beschreibt." },
  { id: "q-ch4-3", q: "Worauf musst du bei YAML besonders achten?", options: ["Einrückung mit Leerzeichen – niemals Tabs.", "Großschreibung aller Schlüssel.", "Semikolon am Zeilenende.", "Maximal 100 Zeilen."], correct: 0, explain: "YAML lebt von Einrückung. Ein Leerzeichen daneben = Fehler. Ada würde weinen." },
  { id: "q-ch4-4", q: "kubectl apply -f app.yaml – zweimal ausgeführt. Was passiert beim zweiten Mal?", options: ["Nichts Schlimmes – „unchanged“, alles stimmt schon.", "Alles wird doppelt erstellt.", "Fehler: apply geht nur einmal.", "Alles wird gelöscht und neu erstellt."], correct: 0, explain: "apply gleicht Soll mit Ist ab und tut nur das Nötige – idempotent." },
  { id: "q-ch5-1", q: "Was ist Helm?", options: ["Der Paketmanager für Kubernetes – installiert komplette Apps als Charts.", "Eine Schutzausrüstung fürs Rechenzentrum.", "Ein Konkurrent von Kubernetes.", "Das Monitoring-Dashboard."], correct: 0, explain: "Helm = Steuerrad – und der App-Store für Kubernetes-Anwendungen." },
  { id: "q-helm-chart-name", q: "Woher hat das Helm-Paket seinen Namen <code>Chart</code>?", options: ["Von „chart“ = Seekarte – passend zum nautischen K8s-Bild: Kubernetes = Steuermann, Helm = Steuerrad, Chart = Seekarte.", "Von „chart“ = Diagramm/Balkengrafik – das Chart zeigt die Auslastung der App.", "Abkürzung für „Container Hierarchy And Resource Template“.", "Nach dem Erfinder, der Herr Chart hieß."], correct: 0, explain: "Englisch <i>chart</i> = <b>Seekarte</b>. Der Helm-„Chart“ (das App-Paket: Chart.yaml + values.yaml + templates/) ist bewusst nautisch benannt – im selben Bild wie <b>Kubernetes</b> (griech. Steuermann) und <b>Helm</b> (Steuerrad), nach der Seekarte, der man folgt. „Chart“ als <b>Diagramm/Grafik</b> ist dasselbe Wort in ANDERER Bedeutung und hier NICHT gemeint." },
  { id: "q-ch5-2", q: "Chart vs. Release?", options: ["Chart = das Paket (Vorlage), Release = eine installierte Instanz davon.", "Release = die Vorlage, Chart = die Installation.", "Charts sind kostenlos, Releases kosten.", "Kein Unterschied."], correct: 0, explain: "Wie Image und Container! Aus einem Chart können mehrere Releases installiert werden." },
  { id: "q-ch5-3", q: "Wozu dient values.yaml in einem Chart?", options: ["Die einstellbaren Werte (Drehknöpfe) – z.B. Anzahl Kopien – ohne die Vorlage zu ändern.", "Der Preis des Charts.", "Die Passwörter des Clusters.", "Das Änderungsprotokoll."], correct: 0, explain: "Gleiche Vorlage + andere Values = Test, Staging, Produktion aus einem Chart." },
  { id: "q-ch5-4", q: "Dein helm upgrade hat alles kaputt gemacht. Panik?", options: ["Nein – helm rollback bringt das Release auf eine frühere Revision zurück.", "Ja – Cluster löschen, neu aufsetzen.", "Alle YAML-Dateien von Hand zurückändern.", "Nur uninstall + neu installieren hilft."], correct: 0, explain: "Helm führt eine Revisions-Historie pro Release. rollback = Lebensretter." },
  { id: "q-helm-create", q: "Woraus besteht ein selbst gebautes Helm-Chart?", options: ["Aus Chart.yaml (Steckbrief), values.yaml (Drehknöpfe) und templates/ (Vorlagen).", "Aus einer einzigen großen YAML-Datei mit allem drin.", "Nur aus einem Dockerfile.", "Aus einem fertigen .tgz, das man nicht ändern kann."], correct: 0, explain: "helm create legt genau dieses Gerüst an: Steckbrief, einstellbare Werte und die Vorlagen werden bewusst getrennt – gleiche Vorlage, andere values = andere Umgebung." },
  { id: "q-helm-lint", q: "Wofür ist helm lint da?", options: ["Es prüft ein Chart auf Fehler und Stil, bevor man es ausrollt oder teilt.", "Es installiert das Chart in den Cluster.", "Es löscht ungenutzte Charts.", "Es zeigt die Logs eines Releases."], correct: 0, explain: "lint ist die Generalprobe fürs Chart: Struktur- und Stilfehler fallen auf, bevor sie im Cluster landen – wie ein Linter für Code." },
  { id: "q-helm-package", q: "Was macht helm package <chart>?", options: ["Es schnürt das Chart in ein versioniertes .tgz-Archiv – zum Teilen oder in ein Repo legen.", "Es startet das Chart als Container.", "Es löscht das Chart vom Cluster.", "Es lädt ein fremdes Chart herunter."], correct: 0, explain: "package erzeugt <name>-<version>.tgz. Genau diese Archive liegen in Chart-Repos – das ist die Brücke vom eigenen Chart zum Verteilen." },
  { id: "q-helm-version-app", q: "Im <code>Chart.yaml</code> stehen <code>version</code> UND <code>appVersion</code> – was ist der Unterschied?", options: ["version = Version des Charts (der Verpackung), appVersion = Version der ausgelieferten App – beide ändern sich unabhängig.", "Zwei Wörter für dasselbe – beide meinen die App-Version.", "version ist für Test, appVersion für Produktion.", "appVersion ist die Helm-Version, mit der man installiert."], correct: 0, explain: "Das Chart ist die Kiste, die App ist die Fracht darin: Du kannst die Kiste umbauen (neue version), ohne die Fracht zu tauschen – oder eine neue App ausliefern (neue appVersion), ohne die Verpackung zu ändern. Häufigste Helm-Verwechslung." },
  { id: "q-helm-semver", q: "Du änderst dein Chart so, dass alte Werte-Dateien NICHT mehr passen (Breaking Change). Welche Stelle der Chart-<code>version</code> (z.B. 2.4.1 = Major.Minor.Patch) ziehst du hoch?", options: ["Die erste – Major (2 → 3). Breaking Change = Major-Bump.", "Die letzte – Patch (1 → 2), das reicht immer.", "Gar keine – Versionen lässt man stehen.", "Eine neue vierte Stelle anhängen."], correct: 0, explain: "SemVer: Major = bricht Bestehendes, Minor = neue Property abwärtskompatibel, Patch = nur ein Wert/Fix. Die Chart-version bei JEDER Änderung hochziehen – sonst sind Rollback, Diffs und Nachvollziehbarkeit dahin." },
  { id: "q-helm-deps", q: "Ein Produkt-Chart bündelt backend, keycloak und geoserver als <code>dependencies:</code> – jedes mit fester Version. Wie nennt man dieses Muster?", options: ["Umbrella-Chart: ein Eltern-Chart zieht mehrere Subcharts (jeweils gepinnt) als ein Paket zusammen.", "Ein Monolith-Chart – alles in einer einzigen templates-Datei.", "Ein Release-Verbund, der ohne Helm auskommt.", "Ein Chart-Repo, also nur eine Sammlung von .tgz-Dateien."], correct: 0, explain: "Wie ein Frachtcontainer voller kleinerer Kisten: Das Umbrella-/Eltern-Chart listet seine Subcharts unter dependencies: mit gepinnter Version. Genau so sind echte Produkt-Deployments gebaut – ein Chart rollt den ganzen Stapel aus." },
  { id: "q-helm-lock", q: "Wozu dienen <code>helm dependency update</code> und <code>Chart.lock</code>?", options: ["Sie holen die Subcharts in den gepinnten Versionen und schreiben sie fest – reproduzierbar, überall gleich.", "Sie sperren das Chart, damit es niemand mehr installieren kann.", "Sie verschlüsseln die values.yaml.", "Sie löschen alte Releases automatisch."], correct: 0, explain: "dependency update liest dependencies: aus dem Chart.yaml, lädt die Subcharts und hält die aufgelösten Versionen in Chart.lock fest – wie ein package-lock.json. Gepinnt = reproduzierbar: derselbe Build ergibt überall denselben Stapel." },
  { id: "q-helm-umbrella-term", q: "Ist „Umbrella Chart“ ein offizieller Helm-Begriff?", options: ["Nein – Industrie-Sprech (auch „Wrapper“/„Bundle“); offiziell heißt es nur parent chart / subcharts / dependencies.", "Ja, „umbrella“ ist ein festes Schlüsselwort im Chart.yaml.", "Ja, es ist ein eigener Chart-Typ neben „application“ und „library“.", "Nein – es ist ein Tippfehler für „assembly chart“."], correct: 0, explain: "Ein Eltern-Chart mit <code>dependencies:</code> nennt man umgangssprachlich <b>Umbrella-Chart</b> (oder „Wrapper“/„Bundle“) – das steht so aber NICHT in der Helm-Doku. Die Spec kennt nur <i>parent chart</i>, <i>subcharts</i> und <i>dependencies</i>. Lerneffekt: gängiger Industrie-Sprech ≠ offizielle Bezeichnung." },
  { id: "q-helm-condition", q: "Wozu dient <code>condition:</code> bei einem Subchart im <code>dependencies:</code>-Block?", options: ["Es schaltet das Subchart per Wert an/aus – so bedient EIN Umbrella-Chart verschiedene Setups.", "Es legt die Reihenfolge fest, in der die Subcharts installiert werden.", "Es prüft, ob die Helm-Version passt.", "Es verschlüsselt die values.yaml des Subcharts."], correct: 0, explain: "<code>condition: permit.enabled</code> macht ein Subchart optional: steht der Wert auf true, wird es mit ausgerollt, sonst nicht. So deckt EIN Umbrella-Chart mehrere Kunden/Umgebungen ab – Kunde mit Permit → an, ohne → aus." },
  { id: "q-helm-subchart-source", q: "Woher kommen die Subcharts eines Umbrella-Charts?", options: ["Entweder „vendored“ (mit im Ordner unter charts/) oder per repository:-URL aus einer Chart-Registry gezogen (helm dependency update).", "Immer nur aus Docker Hub.", "Sie werden zur Laufzeit vom Cluster generiert.", "Nur aus einer einzigen, fest verdrahteten Helm-Zentrale."], correct: 0, explain: "Zwei Wege: <b>vendored</b> – die Subcharts liegen direkt mit im Chart-Ordner (<code>charts/</code>). Oder <b>aus einer Registry</b> – im <code>dependencies:</code>-Eintrag steht eine <code>repository:</code>-URL + Version, und <code>helm dependency update</code> lädt sie herunter und schreibt sie nach <code>Chart.lock</code>." },
  { id: "q-helm-values-overlay", q: "<code>helm install app ./chart -f base.yaml -f prod.yaml</code> – beide Dateien setzen <code>replicas</code>. Welcher Wert zählt?", options: ["Der aus prod.yaml – das spätere -f überlagert das frühere.", "Der aus base.yaml – das erste -f gewinnt.", "Helm bricht mit einem Konflikt-Fehler ab.", "Die Werte werden addiert."], correct: 0, explain: "Mehrere -f werden von links nach rechts übereinandergelegt, das letzte gewinnt. So hält man eine base.yaml mit gemeinsamen Werten und überlagert sie pro Umgebung/Region (values/non-prod, values/prod) – gleiches Chart, andere Werte je Kunde." },
  { id: "q-ch6-1", q: "Was bedeutet „Infrastructure as Code“?", options: ["Server, Netze & Co. werden als Textdateien beschrieben statt zusammengeklickt.", "Programme laufen ohne Betriebssystem.", "Die Infrastruktur schreibt eigenen Code.", "Rechenzentren werden durch Software ersetzt."], correct: 0, explain: "Die Dateien liegen in Git – nachvollziehbar, wiederholbar, teilbar." },
  { id: "q-ch6-2", q: "terraform plan vs. apply?", options: ["plan zeigt nur, was passieren würde – apply führt es aus.", "plan für kleine, apply für große Infrastruktur.", "apply zeigt den Plan, plan wendet an.", "Kein Unterschied."], correct: 0, explain: "Immer erst plan lesen, dann apply. Die Generalprobe vor der Aufführung." },
  { id: "q-ch6-3", q: "Was ist der Terraform-State?", options: ["Terraforms Gedächtnis: was es bereits gebaut hat.", "Der Bundesstaat des Rechenzentrums.", "Eine Statusanzeige der Installation.", "Das Fehlerprotokoll."], correct: 0, explain: "Dank State vergleicht Terraform Soll (.tf-Dateien) mit Ist und setzt nur die Differenz um." },
  { id: "q-ch6-4", q: "Kubernetes und Terraform sind beide deklarativ. Unterschied?", options: ["Kubernetes verwaltet Container im Cluster – Terraform baut die Infrastruktur drumherum.", "Terraform ist nur für Windows-Server.", "Kubernetes ersetzt Terraform.", "Terraform verwaltet nur Datenbanken."], correct: 0, explain: "Terraform baut den Hafen, Kubernetes betreibt den Verkehr darin. Oft baut Terraform sogar den K8s-Cluster." },
  { id: "q-sec-1", q: "Wohin gehören Passwörter und API-Schlüssel im Cluster?", options: ["In Secrets – niemals im Klartext in YAML oder ConfigMaps.", "In die ConfigMap, da sind sie übersichtlich.", "Als Kommentar ins Manifest.", "In den Image-Namen."], correct: 0, explain: "ConfigMaps sind Klartext – Krakenfutter! Vertrauliches gehört in Secrets (und echte Profis verschlüsseln zusätzlich, z.B. mit Sealed Secrets oder Vault)." },
  { id: "q-sec-2", q: "Warum sind Klartext-Passwörter in YAML-Dateien doppelt gefährlich?", options: ["Jede:r mit Cluster- oder Git-Zugriff kann sie lesen – YAML landet ja in Git!", "YAML-Dateien werden automatisch veröffentlicht.", "Passwörter machen YAML-Dateien langsam.", "Sie sind nicht gefährlich."], correct: 0, explain: "Deklarative Dateien gehören in Git – und damit wandert jedes Klartext-Passwort in die Versionshistorie. Für immer. Secrets brechen diese Kette." },
  { id: "q-sec-3", q: "Eine App braucht den DB-Host <code>hafen-db</code> und das DB-Passwort. Was gehört in eine ConfigMap, was in ein Secret?", options: ["DB-Host in die ConfigMap (harmlose Einstellung), das Passwort ins Secret (vertraulich).", "Beides in die ConfigMap – ist übersichtlicher an einem Ort.", "Beides ins Secret – sicher ist sicher.", "DB-Host ins Secret, das Passwort in die ConfigMap."], correct: 0, explain: "Faustregel: nicht-geheime Einstellungen (Hostnamen, Ports, Log-Level, Feature-Flags) → ConfigMap; alles Vertrauliche (Passwörter, Tokens, Schlüssel) → Secret. Beide bindet man gleich ein – z.B. per 'kubectl set env deployment/<name> --from=configmap/<n>' bzw. '--from=secret/<n>'. Eine Truhe nützt nichts, wenn die App nicht reinschaut." },
  { id: "q-ts-1", q: "Ein Pod zeigt CrashLoopBackOff. Was heißt das?", options: ["Die App startet, stürzt ab, startet wieder … – die Ursache steht in den Logs.", "Das Image kann nicht geladen werden.", "Der Pod wartet auf einen freien Node.", "Der Pod wurde absichtlich gestoppt."], correct: 0, explain: "CrashLoop = die App selbst stirbt beim Start (fehlende Config, fehlendes Secret, Bug). kubectl logs verrät, warum." },
  { id: "q-ts-2", q: "Ein Pod zeigt ImagePullBackOff. Häufigste Ursachen?", options: ["Tippfehler im Image-Namen, falscher Tag oder fehlende Registry-Rechte.", "Zu wenig Arbeitsspeicher.", "Der Service ist falsch konfiguriert.", "Das YAML hat Tabs statt Leerzeichen."], correct: 0, explain: "Das Image kann nicht geladen werden – describe zeigt in den Events den genauen Grund. Fix: kubectl set image mit dem richtigen Namen." },
  { id: "q-ts-3", q: "Ein Pod hängt ewig in Pending. Was ist los?", options: ["Er findet keinen Platz – kein Node hat genug Kapazität (oder passt nicht).", "Das Image lädt noch herunter.", "Die App ist abgestürzt.", "Pending ist der Normalzustand."], correct: 0, explain: "Pending = noch nicht eingeplant. describe → Events zeigt z.B. „0/3 nodes are available“. Lösung: Platz schaffen oder Nodes hinzufügen (Terraform!)." },
  { id: "q-ts-4", q: "Das Debugging-Mantra für kaputte Pods?", options: ["get pods → describe → logs, dann fixen und verifizieren.", "Sofort alles löschen und neu deployen.", "Den Cluster neu starten.", "Im Code nach Bugs suchen."], correct: 0, explain: "Erst STATUS lesen (get), dann Events (describe), dann die App-Sicht (logs). Damit findest du 80% aller Ursachen in Minuten." },
  { id: "q-ts-5", q: "Wann hilft kubectl rollout restart?", options: ["Wenn die Ursache behoben ist (z.B. Secret angelegt) und die Pods sauber neu starten sollen.", "Bei jedem Fehler als erstes.", "Nur bei ImagePullBackOff.", "Um den Node neu zu starten."], correct: 0, explain: "Restart ersetzt alle Pods rollierend. Wichtig: ERST die Ursache beheben, sonst crasht es wieder. Reihenfolge: Ursache → Fix → Restart → Verifikation." },
  { id: "q-ts-6", q: "Ein Pod ist READY 0/1, aber STATUS Running – kein Absturz, keine Restarts. Was steckt dahinter?", options: ["Die Readiness-Probe meldet „noch nicht bereit“ – Kubernetes nimmt den Pod so lange aus dem Service.", "Der Pod ist abgestürzt (CrashLoopBackOff).", "Das Image konnte nicht geladen werden (ImagePullBackOff).", "Der Pod findet keinen freien Node (Pending)."], correct: 0, explain: "Liveness fragt „lebt der Pod?“ – schlägt sie fehl, wird neu gestartet. Readiness fragt „kann er schon Anfragen annehmen?“ – schlägt sie fehl, läuft der Pod weiter, wird aber aus dem Service genommen (kein Traffic, READY 0/1). Sichtbar in 'kubectl get endpoints': der Pod fehlt dort. Kein Neustart nötig – die Probe prüft von selbst weiter und lässt ihn rein, sobald er bereit ist." },
  { id: "q-ts-8", q: "<code>kubectl describe pod</code> vs. <code>kubectl logs</code> – worin liegt der Unterschied?", options: ["describe = Kubernetes-Sicht auf den Pod (Zustand + Events, das Warum); logs = was die App selbst ausgibt (stdout/stderr).", "Kein Unterschied – beide zeigen dieselbe Ausgabe.", "describe zeigt die App-Logs, logs zeigt die Kubernetes-Events.", "logs ist nur die Kurzform von describe."], correct: 0, explain: "describe ist die Orchestrierungs-Sicht: Zustand, Image, Limits und die Events (Scheduling, ImagePull, Restarts, OOMKilled, Probes) – also WARUM der Pod in diesem Zustand ist. logs zeigt stdout/stderr der App selbst. Faustregel: erst describe (läuft er überhaupt?), dann logs (was meldet die App?). Bei ImagePullBackOff/Pending/OOMKilled helfen Logs nicht – der Container startet nie." },
  { id: "q-git-1", q: "Was macht git commit?", options: ["Hält die vorgemerkten Änderungen als Schnappschuss mit Nachricht in der Historie fest.", "Lädt die Dateien auf den Server hoch.", "Löscht alle ungespeicherten Änderungen.", "Wechselt auf einen anderen Branch."], correct: 0, explain: "Ein Commit ist ein lokaler Speicherpunkt mit Nachricht. Hochladen zum Server macht erst git push." },
  { id: "q-git-2", q: "Wozu legt man in Git einen eigenen Branch (Zweig) an?", options: ["Um Änderungen abseits von main auszuprobieren und erst nach Review zusammenzuführen.", "Damit Git schneller läuft.", "Um Speicherplatz zu sparen.", "Um Dateien endgültig zu löschen."], correct: 0, explain: "Branches erlauben sicheres, paralleles Arbeiten: main bleibt stabil, das Experiment lebt im Zweig – am Ende wird gemergt." },
  { id: "q-git-3", q: "Unterschied zwischen git add und git commit?", options: ["add merkt Änderungen vor (Staging), commit hält die vorgemerkten dauerhaft in der Historie fest.", "Kein Unterschied, beides speichert dasselbe.", "add committet, commit pusht zum Server.", "add ist für neue Dateien, commit für alte."], correct: 0, explain: "Zwei bewusste Schritte: erst auswählen, was in den Schnappschuss soll (add/Staging), dann festhalten (commit)." },
  { id: "q-git-4", q: "Team-Alltag: Du willst deine Arbeit teilen. Was zuerst – pull oder push?", options: ["Erst git pull (holen), dann git push – sonst bin ich veraltet und der Server weist ab.", "Immer zuerst git push, pull braucht man nur selten.", "Reihenfolge egal, Git sortiert das selbst.", "Weder noch – ein Commit reicht zum Teilen."], correct: 0, explain: "„Erst holen, dann pushen.“ Wer vor dem Push den Stand des Teams holt, vermeidet abgewiesene Pushes und die meisten Konflikte." },
  { id: "q-git-5", q: "Was ist ein Merge-Konflikt?", options: ["Zwei Seiten haben dieselbe Stelle unterschiedlich geändert – Git lässt mich entscheiden, welche gilt.", "Git ist kaputt und das Repository ist verloren.", "Zwei Branches mit demselben Namen.", "Ein abgelehnter git push."], correct: 0, explain: "Kein Drama: Git legt beide Versionen mit Markern (<<<<<<< ======= >>>>>>>) nebeneinander und wartet auf deine Wahl – z.B. git checkout --ours/--theirs, dann add + commit." },
  { id: "q-ci-1", q: "Was löst in GitLab eine Pipeline aus?", options: ["Ein git push in ein Repo, das eine .gitlab-ci.yml enthält.", "Man muss sie jeden Morgen von Hand starten.", "Ein kubectl apply.", "Das Anlegen eines neuen Branches."], correct: 0, explain: "CI heißt Continuous Integration: Bei jedem Push prüft der Runner die .gitlab-ci.yml und arbeitet die Stages automatisch ab – kein Mensch klickt etwas." },
  { id: "q-ci-2", q: "Die typische Stage-Reihenfolge einer CI/CD-Pipeline?", options: ["build → test → deploy", "deploy → test → build", "test → deploy → build", "Die Reihenfolge ist egal."], correct: 0, explain: "Erst bauen (Image erzeugen), dann testen (prüfen, BEVOR etwas live geht), dann deployen (in den Cluster ausrollen). Fällt eine frühe Stage durch, laufen die späteren gar nicht erst." },
  { id: "q-ci-3", q: "Wofür stehen CI und CD?", options: ["Continuous Integration und Continuous Delivery/Deployment.", "Code Inspection und Code Deployment.", "Container Init und Container Deploy.", "Central Integration und Central Delivery."], correct: 0, explain: "CI = Änderungen laufend automatisch bauen & testen. CD = sie automatisch ausliefern/ausrollen. Zusammen: vom Commit bis in den Cluster ohne Handarbeit." },
  { id: "q-tools-ingress", q: "Ein Service ist nur im Cluster erreichbar. Wie kommen Besucher aus dem Internet rein?", options: ["Über einen Ingress – das Hafentor, das z.B. hafen.de/kasse an den richtigen Service weiterleitet.", "Gar nicht, ein Service ist immer öffentlich.", "Über einen zweiten Pod.", "Mit kubectl logs."], correct: 0, explain: "Service = Empfangstresen IM Hafen. Ingress = das Tor nach draußen: eine Adresse + HTTPS-Route von außen auf die passenden Services. Im Job erledigt das ein Ingress-Controller (oft nginx- oder Gateway-basiert)." },
  { id: "q-tools-keycloak", q: "Deine App braucht Login. Was nimmst du, statt selbst eine Benutzerverwaltung zu bauen?", options: ["Keycloak – einen fertigen Auth-/IDP-Server für Anmeldung, Tokens und Rechte.", "Eine Textdatei mit allen Passwörtern.", "Ein zweites Deployment namens login.", "git commit."], correct: 0, explain: "Keycloak ist ein Identity Provider (IDP): zentrale Anmeldung, Single Sign-On, Rollen/Rechte. Man stellt ihn vor die Apps, statt jede App ihren eigenen Login bauen zu lassen." },
  { id: "q-tools-monitoring", q: "Wofür stehen Prometheus und Grafana im Cluster?", options: ["Prometheus sammelt Messwerte (Metriken), Grafana macht daraus Dashboards.", "Beides sind Datenbanken.", "Prometheus ist ein Webserver, Grafana ein Cache.", "Beides sind Paketmanager."], correct: 0, explain: "Monitoring-Duo: Prometheus zapft laufend Metriken an (CPU, Requests, Fehler), Grafana zeigt sie als Diagramme und schlägt Alarm. So siehst du, ob der Hafen gesund ist." },
  { id: "q-tools-stack", q: "PostgreSQL und Redis – welches Tool ist wofür?", options: ["PostgreSQL = Datenbank (Daten dauerhaft), Redis = schneller Zwischenspeicher (Cache).", "PostgreSQL = Cache, Redis = Webserver.", "Beides sind Webserver.", "PostgreSQL = Monitoring, Redis = Login."], correct: 0, explain: "Typischer App-Stack: PostgreSQL hält die Daten dauerhaft, Redis legt Häufiges blitzschnell in den Arbeitsspeicher. nginx davor als Webserver, Keycloak für den Login." },
  { id: "q-netpol", q: "Ohne jede NetworkPolicy – wer darf im Cluster mit wem reden?", options: ["Jeder mit jedem – das Netzwerk ist offen, bis eine NetworkPolicy es einschränkt.", "Niemand – jede Verbindung muss erst freigegeben werden.", "Nur Pods im selben Deployment.", "Nur der Ingress-Controller."], correct: 0, explain: "Kubernetes ist von Haus aus offen: jeder Pod erreicht jeden. Erst eine NetworkPolicy schaltet die ausgewählten Pods auf default-deny und lässt nur erlaubte Quellen durch – so sichert man z.B. Datenbanken ab." },
  { id: "q-netpol-2", q: "Was bestimmt der <code>podSelector</code> einer NetworkPolicy?", options: ["WELCHE Pods die Regel schützt (auf wen sie wirkt).", "WER von außen durchdarf.", "Den Port, der geöffnet wird.", "Den Namen des Ingress-Controllers."], correct: 0, explain: "Der podSelector wählt die geschützten Ziel-Pods (z.B. app=lager). WER zu ihnen durchdarf, steht getrennt in den ingress/from-Regeln. Selektor = WEN man schützt, from = WER rein darf." },
  { id: "q-tls", q: "Was bedeutet <b>TLS-Terminierung</b> am Ingress?", options: ["Der Ingress-Controller wickelt das HTTPS am Eingang ab und reicht intern HTTP an den Service weiter.", "Der Service wird abgeschaltet (terminiert), sobald HTTPS aktiv ist.", "Jeder Pod muss sein eigenes Zertifikat mitbringen.", "TLS verschlüsselt die YAML-Datei auf der Festplatte."], correct: 0, explain: "„Terminieren“ heißt: die TLS-Verschlüsselung endet am Hafentor. Außen verschlüsseltes HTTPS, im Cluster dann normales HTTP. Das Zertifikat liegt als TLS-Secret und wird im Ingress unter spec.tls referenziert." },
  { id: "q-dns", q: "Wie landet ein Hostname wie <code>hafen.de</code> beim richtigen Ingress-Controller?", options: ["DNS löst den Hostnamen zur Adresse des Ingress-Controllers auf; der Controller wählt anhand des Hosts die passende Regel.", "Der Ingress ruft den Browser des Besuchers direkt an.", "Kubernetes verschickt den Hostnamen per E-Mail an alle Nodes.", "Jeder Pod kennt von Geburt an alle Hostnamen."], correct: 0, explain: "DNS ist das Adressbuch des Internets: hafen.de → IP des Ingress-Controllers (im Spiel die feste 203.0.113.10). Beim selben Controller können viele Hosts ankommen – er entscheidet per host-Regel, an welchen Service es geht." },
  /* ---- Phase 6: Wachturm-Quartier (ServiceAccounts, RBAC, Pod-Security) ---- */
  { id: "q-sa-1", q: "Was ist ein <b>ServiceAccount</b> in Kubernetes?", options: ["Die Identität, mit der sich ein Pod beim Kubernetes-API ausweist – ein Ausweis für Programme, nicht für Menschen.", "Das Benutzerkonto, mit dem sich ein Admin am Cluster anmeldet.", "Ein Dienst, der abgestürzte Pods automatisch neu startet.", "Ein spezieller Pod, der Tokens an alle anderen verteilt."], correct: 0, explain: "ServiceAccounts sind Maschinen-Identitäten: ein Pod weist sich damit beim API-Server aus („der bin ich“). Menschen melden sich über User-Accounts/Zertifikate an, Programme im Cluster über ServiceAccounts." },
  { id: "q-sa-2", q: "Du legst einen Pod an, ohne einen <code>serviceAccountName</code> zu setzen. Welche Identität bekommt er?", options: ["Den ServiceAccount <code>default</code> seines Namespaces – den hat jeder Namespace automatisch.", "Gar keine – der Pod kann dann nicht mit dem API reden.", "Die Identität des Admins, der ihn erstellt hat.", "Einen frisch erzeugten, zufällig benannten ServiceAccount."], correct: 0, explain: "Jeder Namespace bringt automatisch einen ServiceAccount namens default mit; ohne Angabe läuft der Pod darunter. Profi-Praxis: Apps, die wirklich API-Rechte brauchen, bekommen einen eigenen SA mit genau den nötigen Rechten – statt dem default Rechte zu geben, die dann jeder Pod erbt." },
  { id: "q-rbac-1", q: "Role vs. ClusterRole – worin unterscheiden sie sich?", options: ["Eine Role gilt nur in EINEM Namespace, eine ClusterRole cluster-weit (alle Namespaces + clusterweite Dinge wie Nodes).", "Eine Role ist für Menschen, eine ClusterRole für Pods.", "Eine Role darf grundsätzlich mehr als eine ClusterRole.", "Kein Unterschied – nur zwei Namen für dasselbe."], correct: 0, explain: "Der Unterschied ist der Geltungsbereich: Role = an einen Namespace gebunden, ClusterRole = gilt überall (und für nicht-namespaced Ressourcen wie Nodes oder PersistentVolumes). Beide beschreiben nur, WAS erlaubt ist – an WEN das geht, regelt erst das Binding." },
  { id: "q-rbac-2", q: "Wozu dient ein <b>RoleBinding</b>?", options: ["Es verknüpft eine Role (die Rechte) mit einem Subjekt (User, Gruppe oder ServiceAccount) – erst dann gelten die Rechte.", "Es erstellt eine neue Role aus einer Vorlage.", "Es löscht abgelaufene Rechte automatisch wieder.", "Es bindet einen Pod fest an einen bestimmten Node."], correct: 0, explain: "Role/ClusterRole sagen nur, WAS man darf. Das Binding klebt diese Rechte an ein konkretes WER. RoleBinding wirkt in einem Namespace, ClusterRoleBinding vergibt die Rechte cluster-weit. Ohne Binding ist eine Role wirkungslos – ein Schlüssel, den niemand in der Hand hält." },
  { id: "q-rbac-3", q: "Was meint das Prinzip <b>Least Privilege</b> bei RBAC?", options: ["Jedes Subjekt bekommt nur genau die Rechte, die es wirklich braucht – nicht mehr.", "Alle bekommen erst Admin-Rechte, das Einschränken kommt später.", "Rechte werden möglichst breit vergeben, damit ja nichts blockiert.", "Nur der Cluster-Admin darf überhaupt irgendetwas."], correct: 0, explain: "„So wenig Rechte wie möglich, so viele wie nötig.“ Darf ein gekaperter Pod nur eine ConfigMap lesen, kann ein Angreifer auch nur das. Breite Rechte wie cluster-admin für alles sind der Krakentraum – ein einziges Leck reicht dann fürs ganze Schiff." },
  { id: "q-rbac-4", q: "Du bist unsicher, ob der ServiceAccount <code>lager</code> Pods löschen darf. Wie prüfst du es, statt zu raten?", options: ["<code>kubectl auth can-i delete pods --as=system:serviceaccount:&lt;ns&gt;:lager</code> – es antwortet schlicht yes/no.", "Einen Pod löschen und schauen, ob es klappt.", "In der Doku des Container-Images nachlesen.", "Den Cluster neu starten und beobachten, was passiert."], correct: 0, explain: "kubectl auth can-i <verb> <resource> fragt den API-Server direkt: „darf ich das?“ Mit --as= prüfst du es stellvertretend für ein anderes Subjekt (z.B. einen ServiceAccount). So verifizierst du Berechtigungen vorher – statt sie im Ernstfall am kaputten Cluster zu erraten." },
  { id: "q-podsec-1", q: "Wofür ist der <code>securityContext</code> eines Pods/Containers da?", options: ["Er legt Sicherheits-Eigenschaften fest – z.B. als welcher User der Container läuft oder ob er Root-Rechte bekommt.", "Er bestimmt, auf welchem Node der Pod landet.", "Er verschlüsselt die Logs des Pods.", "Er regelt, wie viel CPU und RAM der Pod bekommt."], correct: 0, explain: "Der securityContext härtet den Container: runAsNonRoot, runAsUser, readOnlyRootFilesystem, allowPrivilegeEscalation u.a. Ohne ihn läuft vieles per Default als Root – ein gefundenes Fressen für die Krake, sobald die App geknackt wird." },
  { id: "q-podsec-2", q: "Was bewirkt <code>runAsNonRoot: true</code> im securityContext?", options: ["Kubernetes verweigert den Start, wenn der Container als Root (UID 0) laufen würde.", "Es macht den Container automatisch zum Root.", "Es löscht den Root-User aus dem Image.", "Es gibt dem Container zusätzliche Admin-Rechte."], correct: 0, explain: "runAsNonRoot ist die Wache am Tor: Will der Container als Root starten, verweigert Kubernetes den Start mit Fehler. So erzwingst du, dass Apps unprivilegiert laufen – ein Einbrecher im Container ist dann eben nicht gleich Root auf dem Node." },
  { id: "q-podsec-3", q: "Pod Security Standards: Unterschied zwischen <code>baseline</code> und <code>restricted</code>?", options: ["baseline verbietet die schlimmsten Risiken (z.B. privileged), restricted ist strenger und erzwingt zusätzlich Härtung wie runAsNonRoot.", "baseline ist strenger als restricted.", "Beide sind identisch, nur anders benannt.", "restricted erlaubt alles, baseline nichts."], correct: 0, explain: "Drei Stufen: privileged (alles erlaubt), baseline (verbietet bekannte Eskalationen wie privileged-Container oder hostNetwork) und restricted (zusätzlich aktiv gehärtet: non-root, kein Privilege-Escalation, eingeschränkte Capabilities). Zugewiesen wird das pro Namespace per Label." },
  { id: "q-podsec-4", q: "Warum ist ein Container mit <code>privileged: true</code> so gefährlich?", options: ["Er hat nahezu vollen Zugriff auf den Node (Kernel, Geräte) – aus dem Container heraus lässt sich der ganze Host übernehmen.", "Er läuft spürbar langsamer als normale Container.", "Er kann nicht mehr neu gestartet werden.", "Er darf keine Logs mehr schreiben."], correct: 0, explain: "privileged hebt fast alle Isolations-Grenzen auf – der Container agiert wie Root direkt auf dem Node. Wird so ein Pod geknackt, ist faktisch der ganze Node verloren. Echte Apps brauchen das nie; nur seltene Infra-Fälle. baseline und restricted verbieten es deshalb." },
  /* ---- Resource-Management: requests/limits, OOMKilled, HPA & Kosten (#68) ---- */
  { id: "q-ts-7", q: "Ein Pod sammelt RESTARTS und <code>describe</code> zeigt <code>Last State: Terminated, Reason: OOMKilled</code>. Was ist passiert?", options: ["Der Container hat sein memory-Limit gesprengt – der Kernel hat ihn gekillt (Out Of Memory).", "Das Image ließ sich nicht laden (Tippfehler im Namen).", "Die App fehlt ein Secret und stürzt beim Start ab.", "Der Pod findet keinen freien Node."], correct: 0, explain: "OOMKilled = Out Of Memory Killed: Der Container wollte mehr Speicher als sein limits.memory erlaubt, also beendet ihn der Kernel hart (Exit Code 137). Die App-Logs sagen oft nichts – der Beweis steht in 'describe' unter Last State / Reason. Fix: das memory-Limit realistisch anheben (kubectl set resources)." },
  { id: "q-res-1", q: "Was ist der Unterschied zwischen <code>requests</code> und <code>limits</code> bei den Ressourcen eines Containers?", options: ["requests = was der Scheduler fest reserviert (Platzwahl auf dem Node), limits = harte Obergrenze (beim Speicher: drüber → OOMKilled).", "requests ist für CPU, limits nur für Speicher.", "Beides ist dasselbe, limits ist nur das neuere Wort.", "requests ist die Obergrenze, limits der Mindestbedarf."], correct: 0, explain: "requests entscheiden, auf welchem Node ein Pod Platz findet (der Scheduler rechnet damit). limits sind die Obergrenze im Betrieb: CPU drüber wird gedrosselt, Speicher drüber wird hart gekillt (OOMKilled). Zu knapp = Absturz, zu üppig = reservierter Platz, den keiner nutzt." },
  { id: "q-res-cost", q: "Warum sind absichtlich riesige <code>limits/requests</code> „sicherheitshalber\" eine schlechte Idee?", options: ["Reservierter Speicher kostet – große requests blockieren Node-Platz (und damit Dublonen), den niemand nutzt; man dimensioniert nach echtem Bedarf.", "Große Limits machen den Pod automatisch langsamer.", "Kubernetes verbietet Limits über 100Mi.", "Limits haben keinerlei Auswirkung auf Kosten."], correct: 0, explain: "requests reservieren Node-Kapazität fest – wer überall „sicherheitshalber\" 2Gi anfordert, füllt die Nodes mit Luft und zahlt für ungenutzten Platz. Right-Sizing (an echtem Verbrauch messen, dann passend setzen) hält den Cluster stabil UND günstig: knapp genug gegen OOMKilled, klein genug gegen Verschwendung." },
  { id: "q-res-hpa", q: "Wofür ist ein <b>HorizontalPodAutoscaler</b> (HPA) da?", options: ["Er ändert automatisch die Anzahl der Pods (Replicas) je nach Last – z.B. mehr Pods bei hoher CPU/Memory-Auslastung.", "Er vergrößert automatisch das memory-Limit eines einzelnen Pods.", "Er startet abgestürzte Pods neu.", "Er verteilt Secrets an alle Pods."], correct: 0, explain: "Der HPA skaliert HORIZONTAL: er erhöht/senkt die Replica-Zahl anhand gemessener Auslastung (braucht dafür requests als Bezugsgröße). Das ist die Automatik hinter dem manuellen 'kubectl scale'. Vertikal (das Limit eines Pods anpassen) macht stattdessen der VPA – nicht zu verwechseln." },
  /* ---- Phase 4: GitOps-Archipel (GitOps & Argo CD, #99) – situative „Was tust du, wenn …?"-Karten ---- */
  { id: "q-gitops-truth", q: "Du willst wissen, was im Cluster eigentlich laufen <b>soll</b>. Wohin schaust du bei GitOps?", options: ["Ins Git-Repo – dort steht der Soll-Zustand deklarativ als Manifeste.", "<code>kubectl get pods</code> – was gerade läuft, ist der Soll.", "Ins Gedächtnis des Kollegen, der zuletzt etwas deployt hat.", "In die Logs des Ingress-Controllers."], correct: 0, explain: "Git ist die einzige Quelle der Wahrheit (single source of truth): der Soll-Zustand steht deklarativ im Repo. Der Cluster-Ist driftet (Hand-Änderungen, tote Pods) – das Logbuch nicht. Willst du wissen, was sein SOLL, liest du das Repo, nicht den Cluster." },
  { id: "q-gitops-pull", q: "Beim klassischen Deployment <i>pushst</i> du mit <code>kubectl apply</code> von außen in den Cluster. Was passiert beim GitOps-<b>Pull</b> stattdessen?", options: ["Ein Agent im Cluster (z.B. Argo CD) holt sich den Soll-Zustand selbst aus Git und wendet ihn an.", "Der Cluster pusht seinen aktuellen Stand zurück ins Git-Repo.", "Du tippst denselben Befehl, nur über einen Umweg – am Ende ist es dasselbe.", "Ein Mensch muss den Sync jede Nacht von Hand anstoßen."], correct: 0, explain: "Push = von außen reingedrückt (Funkgerät/Pipeline), der Cluster ist passiv. Pull = ein Agent IM Cluster zieht sich den Git-Soll selbst heran und gleicht laufend ab – auch wenn niemand am Funkgerät sitzt. Die Richtung entscheidet, wer die Kontrolle hat." },
  { id: "q-gitops-sync", q: "<code>argocd app get</code> zeigt deine Application als <b>OutOfSync</b>. Was heißt das – und was tust du?", options: ["Cluster-Ist und Git-Soll klaffen auseinander; mit <code>argocd app sync</code> ziehst du den deklarierten Stand in den Cluster.", "Alles ist gut – OutOfSync bedeutet „fertig synchronisiert“.", "Die Application-Datei ist kaputt und muss neu geschrieben werden.", "Argo hat die Verbindung zum Cluster verloren."], correct: 0, explain: "Synced = Ist deckt sich mit dem Git-Soll. OutOfSync = es gibt eine Differenz (z.B. das Deployment fehlt noch im Cluster). <code>argocd app sync</code> holt den im Git deklarierten Stand per Pull herein – das Repo bleibt die Quelle der Wahrheit." },
  { id: "q-gitops-heal", q: "<b>Self-Heal</b> ist aktiv. Du skalierst ein Deployment von Hand auf 0 Replikas. Was passiert?", options: ["Argo erkennt den Drift und stellt automatisch den im Git deklarierten Stand wieder her.", "Das Deployment bleibt auf 0, bis du das Git-Repo änderst.", "Argo aktualisiert das Git-Repo auf 0 Replikas.", "Der ganze Cluster fährt sicherheitshalber herunter."], correct: 0, explain: "Self-Heal ist <i>aktiv</i>, nicht nur Monitoring: weicht der Ist- vom Git-Soll-Zustand ab (Drift), dreht Argo es von selbst zurück – ohne auf einen Menschen zu warten. Argo schreibt dabei nie in Git; Git gewinnt immer." },
  { id: "q-gitops-appofapps", q: "Dein Archipel hat zehn Dienste, jeder als eigene Argo-<code>Application</code>. Du willst sie nicht alle einzeln anlegen und syncen. Was nimmst du?", options: ["Das App-of-Apps-Muster: eine Wurzel-Application zeigt auf einen Ordner voller weiterer Applications – ein Sync zieht die ganze Flotte.", "Alle zehn Dienste in eine einzige riesige YAML-Datei schreiben.", "Jedem Dienst mehr Replikas geben, dann braucht es weniger Applications.", "Self-Heal abschalten, damit der Sync schneller geht."], correct: 0, explain: "Beim App-of-Apps-Muster rollt die Wurzel-Application selbst <i>nichts</i> aus – sie zeigt nur auf einen Ordner voller Kind-Applications, die ihre Dienste selbst ausrollen. Ein neuer Dienst = eine Datei mehr im Ordner, die Wurzel zieht sie beim nächsten Abgleich automatisch mit. Eine Hand am Steuer, die ganze Flotte fährt mit." },
  /* ---- Baustein-Karten (#231): einzelne Flags/Teile eines Befehls, IMMER mit
   *      Kontext (welcher Befehl?) gefragt; ein Flag heißt je Befehl anderes.
   *      In den SR-Pool gehängt über EXTRA_CARDS (game.ts) an genau der Quest,
   *      in der der Baustein eingeführt wird – erst eingeführt, dann abgefragt (#227). ---- */
  { id: "q-flag-ps-a", q: "Bei <code>docker ps</code> – was bewirkt das <code>-a</code>?", options: ["Es zeigt ALLE Container, auch die gestoppten (<code>-a</code> = all).", "Es löscht alle gestoppten Container automatisch.", "Es zeigt die Images statt der Container.", "Es startet alle Container neu."], correct: 0, explain: "<code>-a</code> (all) gehört zu <code>docker ps</code>: Ohne Flag siehst du nur LAUFENDE Container, mit <code>-a</code> auch die gestoppten. Praktisch, um einen abgestürzten Container überhaupt erst zu finden." },
  { id: "q-flag-run-d", q: "Bei <code>docker run</code> – was bewirkt das <code>-d</code>?", options: ["Der Container läuft abgekoppelt im Hintergrund (<code>-d</code> = detached) – das Terminal ist sofort wieder frei.", "Der Container wird nach dem Beenden gelöscht (<code>-d</code> = delete).", "Der Container startet im Debug-Modus.", "Das Image wird vor dem Start neu heruntergeladen."], correct: 0, explain: "<code>-d</code> (detached) gehört zu <code>docker run</code>: Ohne <code>-d</code> hängt dein Terminal am Container und zeigt dessen Ausgabe (blockiert). Mit <code>-d</code> koppelt er sich ab und läuft im Hintergrund – die Konsole ist frei für den nächsten Befehl." },
  { id: "q-flag-run-name", q: "Bei <code>docker run</code> – wozu dient <code>--name meine-kiste</code>?", options: ["Es gibt dem CONTAINER einen frei wählbaren Namen, statt eines zufälligen.", "Es wählt aus, welches Image gestartet wird.", "Es benennt das Image um.", "Es legt den Hostnamen des ganzen Clusters fest."], correct: 0, explain: "<code>--name</code> gehört zu <code>docker run</code> und benennt den CONTAINER, nicht das Image! Ohne <code>--name</code> vergibt Docker einen zufälligen Namen (z.B. „brave_tesla“). Das Image steht dagegen immer ganz hinten im Befehl." },
  { id: "q-flag-build-t", q: "Das Wörtchen „tag“ taucht bei Docker dreimal auf. Was macht das <code>-t</code> in <code>docker build -t hafenwache:1.0 .</code>?", options: ["Es vergibt den ganzen Namen <code>name:tag</code> fürs neue Image (<code>-t</code> = <code>--tag</code>) – der Teil hinter dem <code>:</code> ist der Versions-Tag.", "Es ruft den eigenen Befehl <code>docker tag</code> auf, um einen Zweitnamen zu vergeben.", "Es benennt nur den Versions-Tag, nicht den Namen davor.", "Es startet den frisch gebauten Container im Terminal (<code>-t</code> = terminal)."], correct: 0, explain: "Drei „tag“ sauber getrennt: (1) <code>-t</code> bei <code>docker build</code> (Langform <code>--tag</code>, beide gelten) vergibt den <b>ganzen</b> Namen <code>name:tag</code>. (2) Der Teil hinter dem <code>:</code> (<code>1.0</code>) ist der <b>Versions-Tag</b>. (3) <code>docker tag</code> ist ein <b>eigener Befehl</b>, der einem schon gebauten Image nachträglich einen Zweitnamen gibt (z.B. <code>:latest</code>) – er baut nichts." },
  { id: "q-flag-kubectl-n", q: "Bei <code>kubectl</code> – was macht <code>-n kube-system</code>?", options: ["Es wählt den Namespace, in dem der Befehl arbeitet (hier: kube-system).", "Es begrenzt die Ausgabe auf n Zeilen.", "Es benennt eine Ressource um.", "Es zeigt nur die Nodes an."], correct: 0, explain: "<code>-n &lt;namespace&gt;</code> (Langform <code>--namespace</code>) gehört zu fast allen <code>kubectl</code>-Befehlen. Namespaces unterteilen den Cluster in getrennte Bereiche: Ohne <code>-n</code> arbeitet kubectl im Namespace <code>default</code>; mit <code>-n kube-system</code> schaust du z.B. ins Maschinenherz von Kubernetes." },
  { id: "q-flag-apply-f", q: "Bei <code>kubectl apply</code> – was bedeutet <code>-f app.yaml</code>?", options: ["„from file“: Wende an, was in der Datei app.yaml steht.", "„force“: Erzwinge die Änderung ohne Rückfrage.", "Es filtert die Ausgabe nach dem Wort app.", "Es löscht die Datei nach dem Anwenden."], correct: 0, explain: "<code>-f &lt;datei&gt;</code> (from file) gehört zu <code>kubectl apply</code> (auch <code>create</code>/<code>delete</code>): Es sagt kubectl, den gewünschten Zustand aus dieser YAML-Datei herzustellen. Das ist der deklarative Weg – die Datei ist die Quelle der Wahrheit." },
  { id: "q-flag-helm-set", q: "Bei <code>helm upgrade</code> – was macht <code>--set replicaCount=3</code>?", options: ["Es überschreibt einen einzelnen Wert aus der values.yaml direkt auf der Kommandozeile.", "Es setzt das Release auf eine frühere Revision zurück.", "Es installiert ein zusätzliches Chart.", "Es löscht den angegebenen Wert aus dem Chart."], correct: 0, explain: "<code>--set &lt;schlüssel&gt;=&lt;wert&gt;</code> gehört zu <code>helm install/upgrade</code>: Statt die values.yaml zu ändern, überschreibst du einen einzelnen Drehknopf direkt beim Aufruf – praktisch für schnelle Anpassungen. Für viele/dauerhafte Werte nimmt man eine eigene values-Datei." },
  { id: "q-flag-git-commit-m", q: "Bei <code>git commit</code> – wofür ist <code>-m \"Text\"</code>?", options: ["Es gibt die Commit-Nachricht direkt mit an (<code>-m</code> = message).", "Es merkt alle Dateien für den Commit vor.", "Es führt einen Merge durch.", "Es lädt den Commit zum Server hoch."], correct: 0, explain: "<code>-m \"…\"</code> (message) gehört zu <code>git commit</code>: Es hängt die Beschreibung direkt an den Befehl, statt einen Editor zu öffnen. Jeder Commit braucht eine Nachricht – sie erklärt später, WAS und WARUM geändert wurde." },
  { id: "q-flag-git-checkout-b", q: "Bei <code>git checkout</code> – was bewirkt das <code>-b</code> in <code>git checkout -b feature</code>?", options: ["Es LEGT einen neuen Branch an und wechselt direkt hinein (<code>-b</code> = branch).", "Es wechselt nur auf einen bereits bestehenden Branch.", "Es löscht den angegebenen Branch.", "Es zeigt die Liste aller Branches."], correct: 0, explain: "<code>-b</code> (branch) gehört zu <code>git checkout</code>: Mit <code>-b</code> wird ein NEUER Branch erstellt und du landest sofort darauf. Ohne <code>-b</code> (<code>git checkout &lt;name&gt;</code>) wechselst du nur auf einen schon vorhandenen Branch." },
  { id: "q-flag-git-add-dot", q: "Bei <code>git add</code> – was bedeutet der Punkt in <code>git add .</code>?", options: ["Der Punkt merkt ALLE neuen/geänderten Dateien im Ordner auf einmal vor.", "Der Punkt versteckt die Dateien vor Git.", "Der Punkt steht für eine Datei namens „.“.", "Der Punkt verwirft alle Änderungen."], correct: 0, explain: "Der <code>.</code> bei <code>git add .</code> meint „alles ab dem aktuellen Ordner“: Statt jede Datei einzeln (<code>git add datei1 datei2</code>) merkst du alle neuen/geänderten auf einmal fürs nächste Commit vor. Vorsicht – nimmt wirklich ALLES mit; vorher mit <code>git status</code> prüfen." },
];

/* `explain` begründet im Spaced-Repetition-Feedback das Prinzip (nicht nur die
 * Musterlösung) – „verstehen statt auswendig" (#233). Pflichtfeld pro Karte. */
export const CMD_CARDS = [
  { id: "c-ch1-1", chapter: "q1", q: "Lade das Image <code>nginx</code> aus der Registry herunter.", accept: [/^docker\s+pull\s+nginx(:\S+)?$/], solution: "docker pull nginx", explain: "pull holt ein fertiges Image aus der Registry auf deinen Rechner – build dagegen stellt ein eigenes her." },
  { id: "c-ch1-2", chapter: "q2", q: "Zeige alle laufenden Docker-Container an.", accept: [/^docker\s+ps$/], solution: "docker ps", explain: "ps zeigt nur die laufenden Container; mit -a kämen auch die gestoppten dazu." },
  { id: "c-ch1-3", chapter: "q2", q: "Zeige ALLE Docker-Container – auch gestoppte.", accept: [/^docker\s+ps\s+(-a|--all)$/], solution: "docker ps -a", explain: "Ohne -a siehst du nur laufende Container; erst -a (--all) zeigt auch die gestoppten." },
  { id: "c-ch1-4", chapter: "q3", q: "Starte aus <code>nginx</code> einen Container im Hintergrund namens <code>webserver</code>.", accept: [/^docker\s+run\s+(?:(?:-d|--detach)\s+--name\s+webserver|--name\s+webserver\s+(?:-d|--detach))\s+nginx(:\S+)?$/], solution: "docker run -d --name webserver nginx", explain: "Die Optionen-Reihenfolge ist frei (-d --name oder --name -d, beides gilt) – nur: erst die Optionen, dann das Image (nginx) ganz zuletzt. <code>-d</code> hat auch die Langform <code>--detach</code> (gleichwertig)." },
  { id: "c-ch1-5", chapter: "q3b", q: "Baue aus dem Dockerfile ein Image namens <code>hafenwache:1.0</code> (Baukontext: aktueller Ordner).", accept: [/^docker\s+build\s+(?:-t|--tag)\s+hafenwache:1\.0\s+\.$/], solution: "docker build -t hafenwache:1.0 .", explain: "<code>build</code> baut nicht im Terminal, sondern in der <b>Docker-Engine</b> – einem eigenen Programm, das deine Ordner nicht sieht. Der Punkt am Ende ist der <b>Build-Kontext</b>: der Ordner, den du der Engine als Paket rüberreichst (<code>.</code> = der aktuelle) – die <b>Kiste mit Baumaterial</b>, die du der Werft gibst; ohne sie weiß sie nicht, woraus sie baut. Docker sucht darin das <code>Dockerfile</code>; alles, was <code>COPY</code> reinholt, muss in dieser Kiste liegen. <code>-t</code> (Langform <code>--tag</code>, beides gilt) vergibt den ganzen Namen <code>name:tag</code> – der Teil hinter dem <code>:</code> ist der Versions-Tag; nicht zu verwechseln mit dem eigenen Befehl <code>docker tag</code>, der einem fertigen Image nachträglich einen Zweitnamen gibt." },
  { id: "c-ch1-6", chapter: "q3b", q: "Gib dem Image <code>hafenwache:1.0</code> zusätzlich das Etikett <code>hafenwache:latest</code>.", accept: [/^docker\s+tag\s+hafenwache:1\.0\s+hafenwache:latest$/], solution: "docker tag hafenwache:1.0 hafenwache:latest", explain: "tag vergibt einen zweiten Namen fürs <b>gleiche</b> Image – kein neues Image, kein anderer Stand; <code>:latest</code> ist nur ein Konventions-Name, nicht automatisch die neueste Version. Reihenfolge ist Quelle → Ziel – wie beim Umetikettieren: erst die vorhandene Kiste (hafenwache:1.0), dann das neue Schild (hafenwache:latest)." },
  { id: "c-ch2-1", chapter: "q4", q: "Zeige alle Nodes deines Clusters an.", accept: [/^kubectl\s+get\s+(nodes|node|no)$/], solution: "kubectl get nodes", explain: "get listet Ressourcen eines Typs – hier die Nodes (Server) des Clusters." },
  { id: "c-ch2-2", chapter: "q4", q: "Zeige alle Pods an.", accept: [/^kubectl\s+get\s+(pods|pod|po)$/], solution: "kubectl get pods", explain: "Gleiches Muster wie bei nodes: kubectl get pods listet alle Pods." },
  { id: "c-ch2-3", chapter: "q5", q: "Zeige die Pods im Namespace <code>kube-system</code>.", accept: [/^kubectl\s+get\s+(pods|pod|po)\s+(-n|--namespace)[=\s]?kube-system$/], solution: "kubectl get pods -n kube-system", explain: "-n/--namespace wählt den Namespace; ohne ihn siehst du nur den aktuellen (default)." },
  { id: "c-ch3-1", chapter: "q6", q: "Erstelle ein Deployment <code>shop</code> mit dem Image <code>nginx</code>.", accept: [/^kubectl\s+create\s+deployment\s+shop\s+--image[=\s]nginx(:\S+)?$/], solution: "kubectl create deployment shop --image=nginx", explain: "create deployment legt den Dauerauftrag an; --image bestimmt, welches Image die Pods fahren." },
  { id: "c-ch3-2", chapter: "q6", q: "Skaliere das Deployment <code>shop</code> auf 4 Kopien.", accept: [/^kubectl\s+scale\s+deployment\s+shop\s+--replicas[=\s]4$/], solution: "kubectl scale deployment shop --replicas=4", explain: "scale ändert die Soll-Zahl der Kopien; Kubernetes zieht das Ist sofort nach." },
  { id: "c-ch3-3", chapter: "q7", q: "Stelle einen Service vor das Deployment <code>shop</code>, Port 80.", accept: [/^kubectl\s+expose\s+deployment\s+shop\s+--port[=\s]80$/], solution: "kubectl expose deployment shop --port=80", explain: "expose stellt einen Service als feste Adresse vor das Deployment; --port ist der Port, unter dem er erreichbar ist." },
  { id: "c-ch4-1", chapter: "q8", q: "Wende die Datei <code>app.yaml</code> deklarativ auf den Cluster an.", accept: [/^kubectl\s+apply\s+(?:-f|--filename)\s+app\.yaml$/], solution: "kubectl apply -f app.yaml", explain: "apply gleicht den Cluster an die Datei an – deklarativ und idempotent (zweimal apply schadet nicht)." },
  { id: "c-ch5-1", chapter: "q10", q: "Installiere das Chart <code>bitnami/redis</code> als Release <code>cache</code>.", accept: [/^helm\s+install\s+cache\s+bitnami\/redis$/], solution: "helm install cache bitnami/redis", explain: "install rollt ein Chart als benanntes Release aus – der Release-Name kommt vor dem Chart: helm install <release> <repo>/<chart>." },
  { id: "c-ch5-2", chapter: "q10", q: "Zeige alle installierten Helm-Releases an.", accept: [/^helm\s+(list|ls)$/], solution: "helm list", explain: "list (Kurzform ls) zeigt alle installierten Releases mit Revision und Status." },
  { id: "c-ch5-3", chapter: "q11", q: "Rolle das Release <code>cache</code> auf Revision 1 zurück.", accept: [/^helm\s+rollback\s+cache\s+1$/], solution: "helm rollback cache 1", explain: "Helm führt pro Release eine Revisions-Historie; rollback setzt auf eine frühere Revision zurück – Muster: helm rollback <release> <revision>." },
  { id: "c-ch5-4", chapter: "q21", q: "Lege ein eigenes Chart-Gerüst namens <code>funkdienst</code> an.", accept: [/^helm\s+create\s+funkdienst$/], solution: "helm create funkdienst", explain: "create legt das Chart-Gerüst an: Chart.yaml (Steckbrief), values.yaml (Drehknöpfe) und templates/ (Vorlagen)." },
  { id: "c-ch5-5", chapter: "q21", q: "Prüfe dein Chart <code>funkdienst</code> auf Fehler.", accept: [/^helm\s+lint\s+(\.\/)?funkdienst$/], solution: "helm lint funkdienst", explain: "lint ist die Generalprobe fürs Chart: es prüft Struktur und Stil, bevor du es ausrollst oder teilst." },
  { id: "c-ch5-6", chapter: "q21", q: "Pack dein Chart <code>funkdienst</code> in ein Archiv.", accept: [/^helm\s+package\s+(\.\/)?funkdienst$/], solution: "helm package funkdienst", explain: "package schnürt das Chart in ein versioniertes .tgz – genau das, was in Chart-Repos liegt und sich teilen lässt." },
  { id: "c-ch5-7", chapter: "q21", q: "Installiere aus deinem eigenen Chart <code>./funkdienst</code> ein Release <code>mein-funk</code>.", accept: [/^helm\s+install\s+mein-funk\s+\.\/funkdienst$/], solution: "helm install mein-funk ./funkdienst", explain: "Aus einem lokalen Chart-Ordner installierst du über den Pfad ./<chart> statt über <repo>/<chart>." },
  { id: "c-ch5-8", chapter: "q21", q: "Dein <code>funkdienst</code> ist ein Umbrella-Chart mit Subcharts. Löse die Abhängigkeiten auf und pinne sie (schreibt <code>Chart.lock</code>).", accept: [/^helm\s+(dependency|dep)\s+(update|build|up)\s+(\.\/)?funkdienst$/], solution: "helm dependency update funkdienst", explain: "dependency update liest dependencies: aus dem Chart.yaml, holt die Subcharts und hält die gepinnten Versionen in Chart.lock fest – reproduzierbar wie ein Lockfile." },
  { id: "c-ch5-9", chapter: "q21", q: "Installiere Release <code>hafen-prod</code> aus <code>./funkdienst</code> und überlagere <code>base.yaml</code> mit <code>prod.yaml</code> (Prod-Werte gewinnen).", accept: [/^helm\s+install\s+hafen-prod\s+\.\/funkdienst\s+(?:-f|--values)\s+base\.yaml\s+(?:-f|--values)\s+prod\.yaml$/], solution: "helm install hafen-prod ./funkdienst -f base.yaml -f prod.yaml", explain: "Mehrere -f (Langform <code>--values</code>, gleichwertig) werden von links nach rechts überlagert – das spätere prod.yaml sticht base.yaml. So baut man gleiche Charts mit anderen Werten je Umgebung/Region." },
  { id: "c-ch6-1", chapter: "q12", q: "Initialisiere ein frisches Terraform-Projekt.", accept: [/^terraform\s+init$/], solution: "terraform init", explain: "init ist immer der erste Schritt: es lädt die nötigen Provider/Module ins Projekt." },
  { id: "c-ch6-2", chapter: "q12", q: "Zeige an, was Terraform tun WÜRDE – ohne es zu tun.", accept: [/^terraform\s+plan$/], solution: "terraform plan", explain: "plan ist die Generalprobe: es zeigt, was passieren würde – ohne es wirklich zu tun." },
  { id: "c-ch6-3", chapter: "q13", q: "Setze die Terraform-Konfiguration wirklich um.", accept: [/^terraform\s+apply(\s+-auto-approve)?$/], solution: "terraform apply", explain: "apply setzt die geplante Änderung wirklich um – erst plan lesen, dann apply." },
  { id: "c-sec-1", chapter: "q14", q: "Lege ein Secret <code>api-key</code> mit <code>--from-literal=key=abc123</code> an.", accept: [/^kubectl\s+create\s+secret\s+generic\s+api-key\s+--from-literal[=\s][\w.-]+=\S+$/], solution: "kubectl create secret generic api-key --from-literal=key=abc123", explain: "Secrets halten Vertrauliches – statt Klartext in YAML; --from-literal=<schlüssel>=<wert> setzt einen Wert direkt." },
  { id: "c-sec-2", chapter: "q26", q: "Lege eine ConfigMap <code>app-config</code> mit <code>--from-literal=log_level=info</code> an.", accept: [/^kubectl\s+create\s+configmap\s+app-config\s+--from-literal[=\s][\w.-]+=\S+$/], solution: "kubectl create configmap app-config --from-literal=log_level=info", explain: "ConfigMaps halten harmlose Einstellungen (Klartext, z.B. Log-Level); Vertrauliches gehört stattdessen ins Secret." },
  { id: "c-sec-3", chapter: "q26", q: "Binde die ConfigMap <code>app-config</code> als Umgebung in das Deployment <code>shop</code> ein.", accept: [/^kubectl\s+set\s+env\s+deployment\/shop\s+--from[=\s]configmap\/app-config$/], solution: "kubectl set env deployment/shop --from=configmap/app-config", explain: "set env --from=configmap/<n> bindet die Werte als Umgebungsvariablen ins Deployment – sonst nützt die ConfigMap der App nichts." },
  { id: "c-ts-1", chapter: "q15", q: "Tausche das Image des Deployments <code>shop</code> gegen <code>nginx</code> (Container heißt auch <code>shop</code>).", accept: [/^kubectl\s+set\s+image\s+deployment\/shop\s+\S+=nginx(:\S+)?$/], solution: "kubectl set image deployment/shop shop=nginx", explain: "set image tauscht das Image; das Muster ist <container>=<image> – der Containername steht links vom Gleichheitszeichen." },
  { id: "c-ts-2", chapter: "q16", q: "Starte alle Pods des Deployments <code>shop</code> sauber neu.", accept: [/^kubectl\s+rollout\s+restart\s+deployment[\/\s]shop$/], solution: "kubectl rollout restart deployment shop", explain: "rollout restart ersetzt alle Pods rollierend – z.B. nachdem die Ursache eines Fehlers behoben ist." },
  { id: "c-git-1", chapter: "q18", q: "Mach aus dem aktuellen Ordner ein Git-Repository.", accept: [/^git\s+init$/], solution: "git init", explain: "init macht aus dem Ordner ein Git-Repo (legt den versteckten .git-Ordner an)." },
  { id: "c-git-2", chapter: "q18", q: "Merke die Datei <code>seekarte.md</code> für den nächsten Commit vor.", accept: [/^git\s+add\s+seekarte\.md$/], solution: "git add seekarte.md", explain: "add merkt eine Datei für den nächsten Commit vor (Staging) – erst auswählen, dann mit commit festhalten." },
  { id: "c-git-3", chapter: "q18", q: "Halte die vorgemerkten Änderungen fest (Nachricht: <code>Erste Seekarte</code>).", accept: [/^git\s+commit\s+(?:-m|--message)\s+("[^"]+"|'[^']+'|\S+)$/], solution: 'git commit -m "Erste Seekarte"', explain: "commit hält die vorgemerkten Änderungen als Schnappschuss fest; -m gibt die Nachricht. Hochgeladen wird erst mit push." },
  { id: "c-git-4", chapter: "q19", q: "Lege den Branch <code>experiment-route</code> an und wechsle hinein.", accept: [/^git\s+checkout\s+-b\s+experiment-route$/], solution: "git checkout -b experiment-route", explain: "checkout -b macht beides in einem Schritt: Branch anlegen UND direkt hineinwechseln." },
  { id: "c-git-5", chapter: "q19", q: "Führe <code>experiment-route</code> in deinen aktuellen Branch zusammen.", accept: [/^git\s+merge\s+experiment-route$/], solution: "git merge experiment-route", explain: "merge führt den genannten Branch in deinen aktuellen zusammen – das Experiment kommt zurück in main." },
  { id: "c-ci-1", chapter: "q20", q: "Schau dir den Status der letzten GitLab-Pipeline an.", accept: [/^glab\s+ci\s+status$/], solution: "glab ci status", explain: "Ein Push löst die Pipeline aus; glab ci status zeigt, ob sie durchlief – kein Mensch klickt das an." },
  { id: "c-ci-2", chapter: "q20", q: "Merke ALLE Änderungen auf einmal für den nächsten Commit vor.", accept: [/^git\s+add\s+\.$/], solution: "git add .", explain: "Der Punkt steht für den aktuellen Ordner – damit merkst du alle Änderungen auf einmal vor, statt jede Datei einzeln." },
  { id: "c-git-6", chapter: "q25", q: "Hol die neuen Commits vom Server in deinen aktuellen Branch (holen + zusammenführen).", accept: [/^git\s+pull$/], solution: "git pull", explain: "„Erst holen, dann pushen“: pull holt die neuen Commits und führt sie zusammen – so vermeidest du abgewiesene Pushes." },
  { id: "c-git-7", chapter: "q25", q: "Im Merge-Konflikt: übernimm für <code>seekarte.md</code> die <b>hereinkommende</b> Version.", accept: [/^git\s+checkout\s+--theirs\s+seekarte\.md$/], solution: "git checkout --theirs seekarte.md", explain: "Im Konflikt wählt --theirs die hereinkommende, --ours die eigene Version – danach add + commit." },
  { id: "c-np-1", chapter: "q22", q: "Zeige alle NetworkPolicies (Hafenmauern) im Cluster an.", accept: [/^kubectl\s+get\s+(networkpolicies|networkpolicy|netpol|netpols)$/], solution: "kubectl get networkpolicies", explain: "Gleiches get-Muster: kubectl get networkpolicies (Kurzform netpol) listet die Hafenmauern." },
  { id: "c-np-2", chapter: "q22", q: "Beschreibe die NetworkPolicy <code>hafenmauer</code> – wer darf rein?", accept: [/^kubectl\s+describe\s+(networkpolicy|networkpolicies|netpol|netpols)\s+hafenmauer$/], solution: "kubectl describe networkpolicy hafenmauer", explain: "describe zeigt, wen die Policy schützt (podSelector) und wer durchdarf (from)." },
  { id: "c-res-1", chapter: "q27", q: "Gib dem Deployment <code>kartograf</code> ein memory-Limit von <code>256Mi</code> und einen Request von <code>128Mi</code>.", accept: [/^kubectl\s+set\s+resources\s+deployment\/kartograf\s+(?:--limits[=\s][^\s]*memory=256Mi\s+--requests[=\s][^\s]*memory=128Mi|--requests[=\s][^\s]*memory=128Mi\s+--limits[=\s][^\s]*memory=256Mi)$/], solution: "kubectl set resources deployment/kartograf --limits=memory=256Mi --requests=memory=128Mi", explain: "requests reservieren Platz auf dem Node, limits sind die Obergrenze im Betrieb (Speicher drüber → OOMKilled)." },
];
